arguments.argument:
if global.gamePaused=false
{
  myDir+=swingSpeed
  if type=0 //Down (225,315)
  {
    if myDir>270
    {
      swingSpeed-=0.05
      if swingSpeed<-4 {swingSpeed=-4}
    }
    else
    {
      swingSpeed+=0.05
      if swingSpeed>4 {swingSpeed=4}
    }
  }
  else if type=1 //Up (45,135)
  {
    if myDir>90
    {
      swingSpeed-=0.05
      if swingSpeed<-4 {swingSpeed=-4}
    }
    else
    {
      swingSpeed+=0.05
      if swingSpeed>4 {swingSpeed=4}
    }
  }
  x=initX+lengthdir_x(chainLinks*16,myDir)
  y=initY+lengthdir_y(chainLinks*16,myDir)
}
